Here's a JavaScript code that finds an object by its name deep inside a given object, without using recursion, and returns the path used to reach the object:

```javascript
function findObjectByName(obj, name, path = []) {
  // Check if the current object has the desired name
  if (obj.name === name) {
    // If the object is found, return the path used to reach it
    return path;
  }

  // If the object is not found, iterate over its properties
  for (let prop in obj) {
    // If the property is an object, recursively call the function with the new object and the current path
    if (typeof obj[prop] === 'object') {
      const newPath = [...path, prop];
      const result = findObjectByName(obj[prop], name, newPath);
      if (result !== null) {
        return result;
      }
    }
  }

  // If the object is not found, return null
  return null;
}
```

