  const y = e.clientY - slider.offsetTop;
  const distance = Math.sqrt(x*x + y*y);
  const maxDistance = Math.sqrt(slider.offsetWidth*slider.offsetWidth + slider.offsetHeight*slider.offsetHeight));
  const ratio = distance / maxDistance;
  const newRadius = ratio * 200; // set the new radius based on the distance from the center of the slider
  circle.style.width = newRadius + 'px';
  circle.style.height = newRadius + 'px';
});

slider.addEventListener('mousemove', (e) => {
