Here is a sample function in C# that merges two Word documents into one using OpenXML SDK:

```csharp
using DocumentFormat.OpenXml.Packaging;
using DocumentFormat.OpenXml.Wordprocessing;
using System;
using System.Collections.Generic;
using System.Linq;
using System.Text;
using System.Threading.Tasks;

public static void MergeDocuments(string document1Path, string document2Path, string outputPath)
{
    // Open the first document
    using (WordprocessingDocument doc1 = WordprocessingDocument.Open(document1Path, true)))
    {
        // Get the first 2 pages, header, footer, and design from the first document
        var firstDocumentContent = GetFirstDocumentContent(doc1);

        // Open the second document
        using (WordprocessingDocument doc2 = WordprocessingDocument.Open(document2Path, true))))
        {
            // Get the page contents and glossary from the second document
            var secondDocumentContent = GetSecondDocumentContent(doc2);

            // Merge the contents of the two documents
            var mergedDocumentContent = MergeDocumentContents(firstDocumentContent, secondDocumentContent));

            // Create a new Word document and add the merged content
            using (WordprocessingDocument mergedDocument = WordprocessingDocument.Create(outputPath, WordprocessingDocumentType.Document)))
            {
                // Add the merged content to the new Word document
                var mainPart = mergedDocument.AddMainDocumentPart();
                mainPart.Document = mergedDocumentContent;
            }
        }
    }
}

private static List<Paragraph> GetFirstDocumentContent(WordprocessingDocument doc)
{
    // Get the first 2 pages, header, footer, and design from the first document
    var firstDocumentContent = new List<Paragraph>();

    // Get the first 2 pages
    var firstDocumentPages = doc.MainDocumentPart.Document.Body.Elements<Paragraph>().Take(2);

    // Get the header and footer
    var firstDocumentHeadersFooters = doc.MainDocumentPart.Document.HeaderAndFooter.Descendants<Paragraph>();

    // Get the design (fonts and styles)
    var firstDocumentDesign = doc.MainDocumentPart.Document.Stylesheet.Descendants<Style>().ToList();

    // Add the first 2 pages, header, footer, and design to the first document content
    firstDocumentContent.AddRange(firstDocumentPages);
    firstDocumentContent.AddRange(firstDocumentHeadersFooters));

    return firstDocumentContent;
}

private static List<Paragraph> GetSecondDocumentContent(WordprocessingDocument doc)
{
    // Get the page contents and glossary from the second document
    var secondDocumentContent = new List<Paragraph>();

    // Get the page contents
    var secondDocumentPages = doc.MainDocumentPart.Document.Body.Elements<Paragraph>();

    // Get the glossary
    var secondDocumentGlossary = doc.MainDocumentPart.Document.Descendants<Glossary>().ToList();

    // Add the page contents and glossary to the second document content
    secondDocumentContent.AddRange(secondDocumentPages));
    secondDocumentContent.AddRange(secondDocumentGlossary));

    return secondDocumentContent;
}

private static List<Paragraph> MergeDocumentContents(List<Paragraph> firstDocumentContent, List<Paragraph> secondDocumentContent)
{
    // Merge the contents of the two documents
    var mergedDocumentContent = new List<Paragraph>();

    // Add the first 2 pages, header, footer, and design from the first document
    mergedDocumentContent.AddRange(firstDocumentContent));

    // Add the page contents and glossary from the second document
    mergedDocumentContent.AddRange(secondDocumentContent));

    return mergedDocumentContent;
}
```

This function takes three parameters: the path to the first document, the path to the second document, and the path to the output document.

The function first opens the first document and gets the first 2 pages, header, footer, and design from the first document.

The function then opens the second document and gets the page contents and glossary from the second document.

The function then merges the contents of the two documents and creates a new Word document with the merged content.

Note that this function assumes that the first document contains the first 2 pages, header, footer, and design, and that the second document contains the page contents and glossary. If your documents have different structures, you may need to modify this function accordingly.

