```javascript
function fibonacciMod(n, p) {
  if (n === 0) {
    return 0;
  } else if (n === 1) {
    return 1;
  } else {
    let prev = 0;
    let curr = 1;
    for (let I = 2; I <= n; i++) {
      let next = (prev + curr) % p;
      prev = curr;
      curr = next;
    }
    return curr;
  }
}
