Here's a simple Flask web server with HTTP basic authentication using a python dict for login/password. It also includes an index page.

```python
from flask import Flask, request, Response
import base64

app = Flask(__name__)

# Define a dictionary for login/password
users = {
    "user1": "password1",
    "user2": "password2"
}

# Define a function to check if the user is authenticated
def check_auth(username, password):
    if not (username and password)):
        return False
    return users.get(username) == password

# Define a function to authenticate the user
def authenticate():
    return Response(
        'Please authenticate.\n',
        401,
        {'WWW-Authenticate': 'Basic realm="Login required"'}))

# Define a function to check if the user is authenticated
def requires_auth(f):
    def decorated(*args, **kwargs):
        auth = request.authorization
        if not auth or not check_auth(auth.username, auth.password)):
            return authenticate()
        return f(*args, **kwargs))
    return decorated

# Define the index page
@app.route('/')
@requires_auth
def index():
    return "Hello, World!"

# Run the Flask web server
if __name__ == '__main__':
    app.run(debug=True)
```

