Here is an example Metal compute kernel for Gaussian blur:

```
#include <metal_stdlib>
using namespace metal;

kernel void gaussianBlur(
    texture2d<float, access::read> inputTexture,
    texture2d<float, access::write> outputTexture,
    float sigma,
    uint width,
    uint height)
{
    // Calculate the kernel coefficients
    float sum = 0.0f;
    for (int i = 0; i < 5; i++) {
        float x = i - 2;
        float coeff = exp(-x*x/(2*sigma*sigma)))) / (sigma*sqrt(2*M_PI))));
        sum += coeff;
    }
    float invSum = 1.0f / sum;

    // Calculate the kernel coefficients for each pixel
    for (int y = 0; y < height; y++) {
        for (int x = 0; x < width; x++) {
            float sum = 0.0f;
            for (int i = 0; i < 5; i++) {
                int x2 = x + i - 2;
                int y2 = y + i - 2;
                if (x2 >= 0 && x2 < width && y2 >= 0 && y2 < height) {
                    float coeff = exp(-((i - 2) * (i - 2)) / (2 * sigma * sigma)))) / (sigma * sqrt(2 * M_PI))));
                    sum += coeff * inputTexture.read(x2, y2));
                }
            }
            outputTexture.write(sum * invSum), x, y);
        }
    }
}
```

This kernel takes in an input texture, an output texture, the sigma value for the Gaussian blur, and the dimensions of the input texture. The kernel calculates the kernel coefficients for the Gaussian blur, and then applies the blur to each pixel in the input texture, writing the result to the output texture.

