Here's an example of how to use the strategy pattern in a banking app system:

```
// Define the interface for the strategy
interface TransactionStrategy {
  executeTransaction(amount: number): void;
}

// Define the concrete strategies for different types of transactions
class DepositStrategy implements TransactionStrategy {
  executeTransaction(amount: number): void {
    console.log(`Depositing ${amount} into account`);
  }
}

class WithdrawalStrategy implements TransactionStrategy {
  executeTransaction(amount: number): void {
    console.log(`Withdrawing ${amount} from account`);
  }
}

class TransferStrategy implements TransactionStrategy {
  executeTransaction(amount: number): void {
    console.log(`Transferring ${amount} from account to another`);
  }
}

// Define the context class that uses the strategy pattern
class BankingApp {
  private transactionStrategy: TransactionStrategy;

  constructor(strategy: TransactionStrategy) {
    this.transactionStrategy = strategy;
  }

  public executeTransaction(amount: number): void {
    this.transactionStrategy.executeTransaction(amount);
  }
}

// Use the banking app with different transaction strategies
const depositStrategy = new DepositStrategy();
const withdrawalStrategy = new WithdrawalStrategy();
const transferStrategy = new TransferStrategy();

const bankingApp = new BankingApp(depositStrategy);
bankingApp.executeTransaction(100);

bankingApp.transactionStrategy = withdrawalStrategy;
bankingApp.executeTransaction(50);

bankingApp.transactionStrategy = transferStrategy;
bankingApp.executeTransaction(200);
```

