    type: Date,
    default: Date.now,
  },
});

module.exports = mongoose.model('User', userSchema);
```

5. Create a `controllers` folder and inside it, create a `user.js` file to define the user controller:

```javascript
const User = require('../models/user');

exports.createUser = async (req, res, next) => {
  try {
    const { name, email, password } = req.body;

    const hashedPassword = await bcrypt.hash(password, 10);

    const user = new User({
      name,
      email,
      password: hashedPassword,
    });

    await user.save();

    res.status(201).json({
      message: 'User created successfully!',
      user: {
        id: user.id,
        name: user.name,
        email: user.email,
      },
    });
  } catch (error) {
    next(error);
  }
};

exports.getUserById = async (req, res, next) => {
  try {
    const user = await User.findById(req.params.id).exec();

    if (!user) {
      throw new Error('User not found!');
    }

    res.status(200).json({
      message: 'User found successfully!',
      user: {
        id: user.id,
        name: user.name,
        email: user.email,
      },
    });
  } catch (error) {
    next(error);
  }
};

exports.updateUserById = async (req, res, next) => {
  try {
    const user = await User.findById(req.params.id).exec();

    if (!user) {
      throw new Error('User not found!');
    }

    const { name, email, password } = req.body;

    if (name) {
      user.name = name;
    }

    if (email) {
      user.email = email;
    }

    if (password) {
      const hashedPassword = await bcrypt.hash(password, 10);
      user.password = hashedPassword;
    }

    await user.save();

    res.status(200).json({
      message: 'User updated successfully!',
      user: {
        id: user.id,
        name: user.name,
        email: user.email,
      },
    });
  } catch (error) {
    next(error);
  }
};

exports.deleteUserById = async (req, res, next) => {
  try {
    const user = await User.findById(req.params.id).exec();

    if (!user) {
      throw new Error('User not found!');
    }

    await user.remove();

    res.status(200).json({
      message: 'User deleted successfully!',
    });
  } catch (error) {
    next(error);
  }
};
```

