```rust
use std::io;

fn main() {
    let mut n = String::new();
    println!("Enter the number of prime numbers to generate:");
    io::stdin().read_line(&mut n).expect("Failed to read line");

    let n = n.trim().parse::<u32>().expect("Invalid input");

    let mut primes = vec![];

    for I in 2..=n {
        if is_prime(i) {
            primes.push(i);
        }
    }

    println!("Prime numbers up to {} are: {:?}", n, primes);
}

fn is_prime(n: u32) -> bool {
    if n <= 1 {
        return false;
    }

    for I in 2..=n.sqrt() as u32 {
        if n % I == 0 {
            return false;
        }
    }

    true
}
