Here's a JavaScript function that takes a JSON file and an entity key to search for. The function will recurse map structures to find the entity key. The output will be the value of the key and the JSON key entity location in an array.

```javascript
function searchEntity(json, entityKey) {
  const results = [];

  function recurse(obj, path) {
    if (Array.isArray(obj)) {
      for (let I = 0; I < obj.length; i++) {
        recurse(obj[i], path.concat(i));
      }
    } else if (typeof obj === 'object') {
      for (let key in obj) {
        if (obj.hasOwnProperty(key)) {
          recurse(obj[key], path.concat(key));
        }
      }
    } else {
      if (path.join('.') === entityKey) {
        results.push({ value: obj, path: path });
      }
    }
  }

